SELECT u.*, ste.site_nm AS site_nm, dpt.dept_nm AS dept_nm, rol.role_nm AS role_nm, cd_us.code_label AS user_status_cd_nm, cd_am.code_label AS auth_method_cd_nm FROM sy_user u LEFT JOIN sy_site ste ON ste.site_id = u.site_id LEFT JOIN sy_dept dpt ON dpt.dept_id = u.dept_id LEFT JOIN sy_role rol ON rol.role_id = u.role_id LEFT JOIN sy_code cd_us ON cd_us.code_grp = 'USER_STATUS' AND cd_us.code_value = u.user_status_cd LEFT JOIN sy_code cd_am ON cd_am.code_grp = 'AUTH_METHOD' AND cd_am.code_value = u.auth_method_cd
ORDER BY u.user_id ASC ORDER BY u.user_id DESC ORDER BY u.user_nm ASC ORDER BY u.user_nm DESC ORDER BY u.reg_date ASC ORDER BY u.reg_date DESC ORDER BY u.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

