site_id = #{siteId}, login_id = #{loginId}, user_password = #{userPassword}, user_nm = #{userNm}, user_email = #{userEmail}, user_phone = #{userPhone}, dept_id = #{deptId}, role_id = #{roleId}, user_status_cd = #{userStatusCd}, last_login = #{lastLogin}, login_fail_cnt = #{loginFailCnt}, user_memo = #{userMemo}, upd_by = #{updBy}, upd_date = #{updDate}, auth_method_cd = #{authMethodCd}, last_login_date = #{lastLoginDate},
WHERE user_id = #{userId}
